#include <stdio.h>
#include <stdlib.h>
#define MAXN 500
int abs(int x) { return x < 0 ? -x : x; }
int min(int a, int b) { return a < b ? a : b; }
int max(int a, int b) { return a > b ? a : b; }
int main() {
    int T, N, i, j, k, x, y, steps;
    int matrix[MAXN][MAXN];
    int visited[MAXN][MAXN];
    int queue[MAXN * MAXN][2];
    int front, rear;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                scanf("%d", &matrix[i][j]);
                visited[i][j] = 0;
            }
        }
        front = 0;
        rear = 0;
        queue[rear][0] = 0;
        queue[rear][1] = 0;
        rear++;
        visited[0][0] = 1;
        steps = 0;
        while (front < rear) {
            x = queue[front][0];
            y = queue[front][1];
            front++;
            if (matrix[x][y] == N * N) break;
            for (i = -1; i <= 1; i++) {
                for (j = -1; j <= 1; j++) {
                    if (abs(i) + abs(j) != 1) continue;
                    if (x + i < 0 || x + i >= N || y + j < 0 || y + j >= N) continue;
                    if (visited[x + i][y + j] == 1) continue;
                    queue[rear][0] = x + i;
                    queue[rear][1] = y + j;
                    rear++;
                    visited[x + i][y + j] = 1;
                }
            }
            steps++;
        }
        printf("%d\n", steps);
    }
    return 0;
}

