import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] matrix = new int[N][N];
            int[][] visited = new int[N][N];
            Queue<int[]> q = new LinkedList<>();
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    matrix[i][j] = sc.nextInt();
                    visited[i][j] = 0;
                }
            }
            q.add(new int[] {0, 0});
            visited[0][0] = 1;
            int steps = 0;
            while (!q.isEmpty()) {
                int[] curr = q.poll();
                int x = curr[0];
                int y = curr[1];
                if (matrix[x][y] == N * N) break;
                for (int i = -1; i <= 1; i++) {
                    for (int j = -1; j <= 1; j++) {
                        if (Math.abs(i) + Math.abs(j) != 1) continue;
                        if (x + i < 0 || x + i >= N || y + j < 0 || y + j >= N) continue;
                        if (visited[x + i][y + j] == 1) continue;
                        q.add(new int[] {x + i, y + j});
                        visited[x + i][y + j] = 1;
                    }
                }
                steps++;
            }
            System.out.println(steps);
        }
    }
}

