    const N = parseInt(readline());
    const matrix = [];
    for (let j = 0; j < N; j++) {
        matrix.push(readline().split(' ').map(x => parseInt(x)));
    }
    const visited = Array(N).fill(0).map(() => Array(N).fill(0));
    const q = [];
    q.push([0, 0]);
    visited[0][0] = 1;
    let steps = 0;
    while (q.length > 0) {
        const [x, y] = q.shift();
        if (matrix[x][y] === N * N) break;
        for (let k = -1; k <= 1; k++) {
            for (let l = -1; l <= 1; l++) {
                if (Math.abs(k) + Math.abs(l) !== 1) continue;
                if (x + k < 0 || x + k >= N || y + l < 0 || y + l >= N) continue;
                if (visited[x + k][y + l] === 1) continue;
                q.push([x + k, y + l]);
                visited[x + k][y + l] = 1;
            }
        }
        steps++;
    }
    console.log(steps);
